mapper.select:
SELECT role
FROM company_user
WHERE user_id = #{userId}
AND company_id = #{companyId}
AND status = 1
LIMIT 1

SELECT COUNT(*)
FROM company_user
WHERE user_id = #{userId}
AND company_id = #{companyId}
AND status = 1

SELECT u.id, u.user_account, u.username, u.email, u.avater, u.telephone, u.birthday, u.sex, u.role, u.sign, u.region, u.disabled, u.permission, u.create_date, u.update_date FROM company_user cu INNER JOIN user u ON cu.user_id = u.id WHERE cu.company_id = #{companyId} AND cu.status = 1 AND u.disabled = 0
AND ( u.username LIKE CONCAT('%', #{keyword}, '%') OR u.user_account LIKE CONCAT('%', #{keyword}, '%') OR u.telephone LIKE CONCAT('%', #{keyword}, '%') OR u.email LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY cu.role DESC, cu.join_date ASC LIMIT #{offset}, #{pageSize}
